// Description: Collects JVM heap, threads, CPU, and disk metrics from Nexus system-information API.
// Description: Requires nx-atlas-all privilege for the Atlas endpoint.
import groovy.json.JsonSlurper
import javax.net.ssl.*
import java.security.cert.X509Certificate

def host = hostProps.get("nexus.host")
def user = hostProps.get("nexus.user")
def pass = hostProps.get("nexus.pass")
def port = hostProps.get("nexus.port") ?: "8081"
def useSsl = (hostProps.get("nexus.ssl") ?: "true").toLowerCase() == "true"

def results = [
    "heap_used_bytes": 0,
    "heap_max_bytes": 0,
    "heap_used_pct": 0,
    "thread_count": 0,
    "cpu_cores": 0,
    "disk_total_bytes": 0,
    "disk_usable_bytes": 0,
    "disk_used_pct": 0
]

if (!host || !user || !pass) {
    results.each { k, v -> println("${k}:${v}") }
    return 0
}

def credentials = "${user}:${pass}".bytes.encodeBase64().toString()

def trustAllCerts = [
    checkClientTrusted: { chain, authType -> },
    checkServerTrusted: { chain, authType -> },
    getAcceptedIssuers: { null }
] as X509TrustManager

def sc = SSLContext.getInstance("TLS")
sc.init(null, [trustAllCerts] as TrustManager[], null)
HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory())
HttpsURLConnection.setDefaultHostnameVerifier({ hostname, session -> true } as HostnameVerifier)

def proto = useSsl ? "https" : "http"
def baseUrl = "${proto}://${host}:${port}"

def nexusGet(String path, String baseUrl, String credentials) {
    try {
        def url = new URL("${baseUrl}${path}")
        def conn = url.openConnection()
        conn.setRequestProperty("Authorization", "Basic ${credentials}")
        conn.setRequestProperty("Accept", "application/json")
        conn.setConnectTimeout(30000)
        conn.setReadTimeout(30000)
        if (conn.responseCode == 200) {
            return new JsonSlurper().parseText(conn.inputStream.text)
        } else {
            System.err.println("Nexus API error: HTTP ${conn.responseCode} for ${path}")
        }
    } catch (Exception e) {
        System.err.println("Nexus API error for ${path}: ${e.message}")
    }
    return null
}

def sysInfo = nexusGet("/service/rest/atlas/system-information", baseUrl, credentials)

if (sysInfo != null) {
    def runtime = sysInfo["system-runtime"]
    if (runtime) {
        def totalMem = runtime.totalMemory ?: 0
        def freeMem = runtime.freeMemory ?: 0
        def maxMem = runtime.maxMemory ?: 0
        def heapUsed = totalMem - freeMem

        results["heap_used_bytes"] = heapUsed
        results["heap_max_bytes"] = maxMem
        results["heap_used_pct"] = (maxMem > 0) ? ((heapUsed / maxMem) * 100).round(2) : 0
        results["thread_count"] = runtime.threads ?: 0
        results["cpu_cores"] = runtime.availableProcessors ?: 0
    }

    def filestores = sysInfo["system-filestores"]
    if (filestores && filestores.size() > 0) {
        // Filestores is a dict keyed by mount name; find the primary non-virtual filesystem
        def primary = filestores.values().find { it.totalSpace > 0 && !it.readOnly }
        if (!primary) primary = filestores.values().first()
        def totalSpace = primary.totalSpace ?: 0
        def usableSpace = primary.usableSpace ?: 0

        results["disk_total_bytes"] = totalSpace
        results["disk_usable_bytes"] = usableSpace
        results["disk_used_pct"] = (totalSpace > 0) ? (((totalSpace - usableSpace) / totalSpace) * 100).round(2) : 0
    }
}

results.each { k, v -> println("${k}:${v}") }
return 0
